$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_83112255bb4233cad4276eab160483e8'] = 'Active ou désactive le nettoyeur. Lorsque cette option est désactivée, l’URL cron et le bouton d’exécution manuelle ne supprimeront pas les anciennes statistiques. Utilisez ce commutateur pour garder le module installé tout en arrêtant temporairement toute activité de nettoyage.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_896e1fd6ab19d8bbd2f58f989fbaac76'] = 'Jours de conservation des statistiques de connexion';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_b878a67f82524d412dae79ad597ff402'] = 'Les lignes plus anciennes que cette valeur seront supprimées de connections, connections_source et connections_page.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_5ee406d769ac3887713d3308a0d01601'] = 'Indiquez le nombre de jours pendant lesquels les statistiques brutes de visiteurs PrestaShop doivent être conservées. Exemple : 60 signifie que le module conserve les 60 derniers jours et supprime les anciens enregistrements de ps_connections, ps_connections_source et ps_connections_page. Ne mettez pas 1 sauf si vous êtes sûr de ne pas avoir besoin des statistiques récentes.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_1300769d8d72fc8218b40772f1c25efc'] = 'Taille du lot';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_631c4c75cb36e0fcee3da42ef67e730e'] = 'Nombre maximal de connexions traitées dans un lot.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_acbc6e359c79ace4ef9b5398148c13e2'] = 'Indiquez combien d’enregistrements principaux de connexion peuvent être traités dans un lot interne. Les petites valeurs sont plus sûres sur un hébergement faible mais nécessitent plus d’exécutions cron. Les grandes valeurs nettoient plus vite mais peuvent maintenir des verrous de base de données plus longtemps. Valeur de départ recommandée : 1000 à 5000 ; augmentez seulement après avoir testé le temps d’exécution.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_2806977593fb4c23003cc11306b135d1'] = 'Nombre maximal de lots par exécution';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d31a094a19379b58b63b51ef0f9d9362'] = 'Limite la quantité de travail qu’une exécution cron peut effectuer.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_e221a5a91ea62a43adc5bb15614eb578'] = 'Indiquez combien de lots peuvent s’exécuter pendant une exécution cron. Le total possible de connexions principales supprimées par exécution est environ Taille du lot multipliée par Nombre maximal de lots. Exemple : 5000 et 10 signifie jusqu’à environ 50000 enregistrements de connexion principaux en une exécution cron. Réduisez cette valeur si la boutique ralentit pendant le nettoyage.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a1a47524ffa9c839887703df1fbe70a3'] = 'Vider ps_layered_filter_block';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_924684322fe68e56ef9205e7f480f598'] = 'Vide le cache du bloc de recherche à facettes/layered avec TRUNCATE TABLE. La table est recréée vide par MySQL/MariaDB.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_92a6452eb793565a92aa28e5f9a3f2e5'] = 'Activez uniquement si ps_layered_filter_block devient trop volumineuse ou contient un cache de recherche à facettes obsolète. Cela ne supprime pas les produits, catégories ni l’index des prix layered. Après le nettoyage, PrestaShop ou le module de recherche à facettes peut reconstruire ce cache si nécessaire.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_bf45506cce2494894a9df6ff4bdf83ae'] = 'Agréger les statistiques des sources de trafic avant suppression';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d7e1a0c7e7973ebcde37aa659525105d'] = 'Stocke des statistiques quotidiennes résumées des sources de trafic avant de supprimer les lignes brutes.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ae729759e10d7a626a8622321932a1f4'] = 'Lorsque cette option est activée, le module enregistre un petit résumé quotidien avant de supprimer les statistiques brutes PrestaShop. Il conserve des compteurs comme les visites, vues de pages, domaine source et valeurs UTM. Il ne stocke pas les adresses IP, les URL de référent complètes ni les chaînes user-agent. Désactivez si vous voulez seulement supprimer et n’avez pas besoin d’historique des sources.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ce2b282d224153cccd645f28504ab4e2'] = 'Jours de conservation des statistiques agrégées';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_c3b4d14f7bff29c221039e891918f2dd'] = 'Durée de conservation de la petite table de résumé quotidien.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a97a6a6ab09f48206a543fdc7321bb60'] = 'Indiquez combien de jours les résumés agrégés des sources de trafic doivent rester dans la table du module. Exemple : 730 conserve environ deux ans de résumés quotidiens. Ce réglage ne concerne que la table ps_jooim_dbcleaner_traffic_daily, pas les tables statistiques PrestaShop originales.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_4d4c70d739ad72835a8b62a81e07c611'] = 'Expiration du verrou obsolète en secondes';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ef4f59605eb7e54ec7df26e3755b7edf'] = 'Protection contre deux processus de nettoyage exécutés en même temps.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_2c1824ea38ec688698a26f01a46e6b16'] = 'Indiquez le nombre de secondes après lequel un verrou de nettoyage non terminé est considéré comme abandonné. Cela protège la base de données contre deux exécutions cron simultanées. Valeur recommandée : 7200. Réduisez-la seulement si votre cron se termine toujours rapidement.';
