$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ae729759e10d7a626a8622321932a1f4'] = 'Lorsque cette option est activée, le module enregistre un petit résumé quotidien avant de supprimer les statistiques brutes PrestaShop. Il conserve des compteurs comme les visites, vues de pages, domaine source et valeurs UTM. Il ne stocke pas les adresses IP, les URL de référent complètes ni les chaînes user-agent. Désactivez si vous voulez seulement supprimer et n’avez pas besoin d’historique des sources.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ce2b282d224153cccd645f28504ab4e2'] = 'Jours de conservation des statistiques agrégées';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_c3b4d14f7bff29c221039e891918f2dd'] = 'Durée de conservation de la petite table de résumé quotidien.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_a97a6a6ab09f48206a543fdc7321bb60'] = 'Indiquez combien de jours les résumés agrégés des sources de trafic doivent rester dans la table du module. Exemple : 730 conserve environ deux ans de résumés quotidiens. Ce réglage ne concerne que la table ps_jooim_dbcleaner_traffic_daily, pas les tables statistiques PrestaShop originales.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_4d4c70d739ad72835a8b62a81e07c611'] = 'Expiration du verrou obsolète en secondes';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ef4f59605eb7e54ec7df26e3755b7edf'] = 'Protection contre deux processus de nettoyage exécutés en même temps.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_2c1824ea38ec688698a26f01a46e6b16'] = 'Indiquez le nombre de secondes après lequel un verrou de nettoyage non terminé est considéré comme abandonné. Cela protège la base de données contre deux exécutions cron simultanées. Valeur recommandée : 7200. Réduisez-la seulement si votre cron se termine toujours rapidement.';
